// CF12 WF_HOOK_ANALYZER — normalize trigger, idempotency, fetch topic + scenes.
// Group scenes by chapter, extract first 2 scenes per chapter as hook opening.
// Global fetch + $env per MEMORY.md.

const raw = $input.first().json;
const viaWebhook = !!raw.body;
const payload = raw.body || raw;

const topicId = payload.topic_id;
const force = payload.force === true;

if (!topicId) {
  return [{
    json: {
      success: false,
      error: 'Provide { topic_id }',
      http_status: 400,
      via_webhook: viaWebhook
    }
  }];
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

async function sbGet(url, label) {
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) throw new Error(`${label} failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`);
  return res.json();
}

// 1. Fetch topic
const topicUrl = `${supabaseUrl}/rest/v1/topics?id=eq.${topicId}&select=id,project_id,seo_title,selected_title,script_json,script_metadata,hook_scores,avg_hook_score,weak_hook_count,hook_analyzed_at`;
const topics = await sbGet(topicUrl, 'fetch topic');
const topic = Array.isArray(topics) && topics[0] ? topics[0] : null;

if (!topic) {
  return [{ json: { success: false, error: `Topic ${topicId} not found`, http_status: 404, via_webhook: viaWebhook } }];
}

// 2. Idempotency
if (!force && topic.hook_analyzed_at) {
  return [{
    json: {
      success: true,
      skipped: true,
      reason: 'Hooks already analyzed (pass force=true to re-analyze)',
      topic_id: topicId,
      project_id: topic.project_id,
      hook_scores: topic.hook_scores,
      avg_hook_score: topic.avg_hook_score,
      weak_hook_count: topic.weak_hook_count,
      hook_analyzed_at: topic.hook_analyzed_at,
      http_status: 200,
      via_webhook: viaWebhook
    }
  }];
}

const projectId = topic.project_id;

// 3. Fetch project context for niche
let project = {};
try {
  const projArr = await sbGet(`${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description`, 'fetch project');
  project = (projArr && projArr[0]) || {};
} catch (_) { }

// 4. Fetch scenes ordered
const scenesUrl = `${supabaseUrl}/rest/v1/scenes?topic_id=eq.${topicId}&select=scene_number,narration_text,chapter&order=scene_number.asc&limit=500`;
let scenes = [];
try {
  scenes = await sbGet(scenesUrl, 'fetch scenes');
} catch (e) {
  return [{ json: { success: false, error: `Failed to fetch scenes: ${e.message}`, http_status: 500, via_webhook: viaWebhook } }];
}

if (!Array.isArray(scenes) || scenes.length === 0) {
  return [{ json: { success: false, error: 'No scenes found for topic — cannot analyze hooks', http_status: 422, via_webhook: viaWebhook } }];
}

// 5. Group scenes by chapter. Fall back to global "Chapter 1 Opener" if no chapter metadata.
const hasChapters = scenes.some(s => s.chapter && String(s.chapter).trim() !== '');

const chapters = [];
if (hasChapters) {
  const byChapter = new Map();
  const order = [];
  for (const s of scenes) {
    const name = String(s.chapter || '').trim() || 'Unassigned';
    if (!byChapter.has(name)) {
      byChapter.set(name, []);
      order.push(name);
    }
    byChapter.get(name).push(s);
  }
  for (let i = 0; i < order.length; i++) {
    const name = order[i];
    const list = byChapter.get(name);
    const first2 = list.slice(0, 2).map(x => x.narration_text || '').join(' ').trim();
    const opening = first2.slice(0, 400);
    if (opening.length > 0) {
      chapters.push({
        name,
        chapter_index: i,
        opening_text: opening
      });
    }
  }
} else {
  const first3 = scenes.slice(0, 3).map(x => x.narration_text || '').join(' ').trim();
  chapters.push({
    name: 'Chapter 1 Opener',
    chapter_index: 0,
    opening_text: first3.slice(0, 400)
  });
}

if (chapters.length === 0) {
  return [{ json: { success: false, error: 'No chapter openings could be extracted', http_status: 422, via_webhook: viaWebhook } }];
}

return [{
  json: {
    topic_id: topicId,
    project_id: projectId,
    topic,
    project,
    chapters,
    has_chapters: hasChapters,
    scene_count: scenes.length,
    via_webhook: viaWebhook,
    force,
    started_at: new Date().toISOString()
  }
}];

// Single Opus 4.6 call scores all chapter hooks on 5 dimensions. Inline backoff.
const data = $input.first().json;
if (data.success === false || data.skipped) return $input.item;

const anthropicKey = $env.ANTHROPIC_API_KEY;
const sleep = (ms) => new Promise(r => setTimeout(r, ms));

const topic = data.topic || {};
const project = data.project || {};
const chapters = data.chapters || [];

const seoTitle = topic.selected_title || topic.seo_title || '(untitled)';
const nicheContext = project.niche_description || project.niche || 'general audience';

const chaptersBlock = chapters
  .map((c, i) => `[${i + 1}] ${c.name}:\n"${c.opening_text}"`)
  .join('\n\n');

const prompt = `You are a viral YouTube hook writing coach. Score each chapter opening on 5 hook dimensions. Be strict — most openings score 50-65. A 90+ score is rare.

Topic: ${seoTitle}
Niche: ${nicheContext}

Chapters to score:
${chaptersBlock}

For EACH chapter opening, score these 5 dimensions (each 0-20):
1. curiosity_gap — does it open a loop viewer must close by watching?
2. emotional_trigger — fear, surprise, curiosity, validation, or desire activated?
3. specificity — concrete numbers/names/places rather than vague claims?
4. pattern_interrupt — breaks listener's expected narrative flow?
5. open_loop — implicit "but wait, what happens next?" left dangling?

Total per chapter = sum of 5 dimensions (0-100).
weak_flag = total_score < 60.
For weak hooks, provide a one-sentence rewrite_suggestion that preserves content but strengthens hook.

Return ONLY valid JSON (no markdown fences):
{
  "chapters": [
    {
      "chapter_name": "<name>",
      "chapter_index": <int>,
      "opening_text": "<first 150 chars of input>",
      "breakdown": {"curiosity_gap": <int>, "emotional_trigger": <int>, "specificity": <int>, "pattern_interrupt": <int>, "open_loop": <int>},
      "total_score": <int>,
      "weak_flag": <bool>,
      "rewrite_suggestion": "<only if weak_flag=true, else empty string>"
    }
  ],
  "avg_score": <int>,
  "weakest_chapter_index": <int>,
  "overall_summary": "<1 sentence on the strongest and weakest hooks>"
}`;

async function callClaude(maxRetries = 4) {
  let lastErr = null;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': anthropicKey,
          'anthropic-version': '2023-06-01',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-opus-4-6',
          max_tokens: 2500,
          messages: [{ role: 'user', content: prompt }]
        })
      });
      if (res.ok) {
        const body = await res.json();
        return { ok: true, text: body.content?.[0]?.text || '', attempts: attempt };
      }
      const errBody = await res.text();
      if (res.status === 429) await sleep(30000);
      lastErr = new Error(`HTTP ${res.status}: ${errBody.slice(0, 300)}`);
      if (res.status >= 400 && res.status < 500 && res.status !== 429) break;
    } catch (e) { lastErr = e; }
    if (attempt < maxRetries) await sleep(Math.min(1000 * Math.pow(2, attempt - 1), 30000));
  }
  return { ok: false, error: lastErr?.message || 'opus_hook_analyzer failed', attempts: maxRetries };
}

function parseJson(text) {
  if (!text) return null;
  const clean = text.replace(/```json|```/g, '').trim();
  try { return JSON.parse(clean); } catch {}
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) { try { return JSON.parse(m[0]); } catch {} }
  return null;
}

function clampDim(n) { const v = Number(n) || 0; return Math.max(0, Math.min(20, Math.round(v))); }

