const opusRes = await callClaude(4);
const parsed = opusRes.ok ? parseJson(opusRes.text) : null;

let chapterResults = [];
let overallSummary = '';
let weakestIdx = 0;

if (parsed && Array.isArray(parsed.chapters) && parsed.chapters.length > 0) {
  // Clamp dimensions and recompute total authoritatively
  chapterResults = parsed.chapters.map((c, i) => {
    const bd = c.breakdown || {};
    const breakdown = {
      curiosity_gap: clampDim(bd.curiosity_gap),
      emotional_trigger: clampDim(bd.emotional_trigger),
      specificity: clampDim(bd.specificity),
      pattern_interrupt: clampDim(bd.pattern_interrupt),
      open_loop: clampDim(bd.open_loop)
    };
    const total = breakdown.curiosity_gap + breakdown.emotional_trigger + breakdown.specificity + breakdown.pattern_interrupt + breakdown.open_loop;
    const weak = total < 60;
    return {
      chapter_name: String(c.chapter_name || chapters[i]?.name || `Chapter ${i + 1}`).slice(0, 200),
      chapter_index: Number.isInteger(c.chapter_index) ? c.chapter_index : i,
      opening_text: String(c.opening_text || chapters[i]?.opening_text || '').slice(0, 400),
