    chapter_name: c.name,
    chapter_index: c.chapter_index,
    opening_text: c.opening_text.slice(0, 400),
    breakdown: {
      curiosity_gap: 12,
      emotional_trigger: 12,
      specificity: 12,
      pattern_interrupt: 12,
      open_loop: 12
    },
    total_score: 60,
    weak_flag: false,
    rewrite_suggestion: ''
  }));
