    weakestIdx = parsed.weakest_chapter_index;
  } else {
    // Derive from lowest total_score
    let minIdx = 0;
    let minVal = Infinity;
    chapterResults.forEach((c, i) => { if (c.total_score < minVal) { minVal = c.total_score; minIdx = i; } });
    weakestIdx = minIdx;
  }
} else {
  // Fallback: neutral 60s per chapter, no rewrite suggestions
  chapterResults = chapters.map((c, i) => ({
    chapter_name: c.name,
    chapter_index: c.chapter_index,
    opening_text: c.opening_text.slice(0, 400),
    breakdown: {
      curiosity_gap: 12,
      emotional_trigger: 12,
      specificity: 12,
      pattern_interrupt: 12,
      open_loop: 12
    },
    total_score: 60,
    weak_flag: false,
    rewrite_suggestion: ''
  }));
  overallSummary = 'Hook analyzer fallback — Opus call failed or returned invalid JSON';
  weakestIdx = 0;
}

const totals = chapterResults.map(c => c.total_score);
const avgHookScore = totals.length ? Math.round(totals.reduce((a, b) => a + b, 0) / totals.length) : 0;
const weakHookCount = chapterResults.filter(c => c.weak_flag).length;

const opusOk = !!parsed;
const opusCostUsd = opusOk ? 0.05 : 0;

return [{
  json: {
    ...data,
    hook_scores_envelope: {
      chapters: chapterResults,
      avg_score: avgHookScore,
      weakest_chapter_index: weakestIdx,
      overall_summary: overallSummary
    },
    avg_hook_score: avgHookScore,
    weak_hook_count: weakHookCount,
    opus_ok: opusOk,
    opus_error: opusOk ? null : (opusRes.error || 'parse_failed'),
    opus_duration_ms: Date.now() - opusStart,
    opus_cost_usd: opusCostUsd
  }
}];

// PATCH topic with hook_scores envelope + scalar helpers. Log to production_logs.
const data = $input.first().json;
if (data.success === false) return [{ json: data }];
if (data.skipped) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const topicId = data.topic_id;
const projectId = data.project_id;
const envelope = data.hook_scores_envelope;
const nowIso = new Date().toISOString();

const patch = {
  hook_scores: envelope,
  avg_hook_score: data.avg_hook_score,
  weak_hook_count: data.weak_hook_count,
  hook_analyzed_at: nowIso
};

let patchError = null;
try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  patchError = e.message;
}

// production_logs
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'hook_analyzer',
      scene_number: null,
      action: 'opus_5dim',
      status: patchError ? 'partial' : (data.opus_ok ? 'success' : 'fallback'),
      duration_ms: data.opus_duration_ms || 0,
      cost_usd: data.opus_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !patchError,
    topic_id: topicId,
    project_id: projectId,
    hook_scores: envelope,
    avg_hook_score: data.avg_hook_score,
    weak_hook_count: data.weak_hook_count,
    hook_analyzed_at: nowIso,
    opus_ok: data.opus_ok,
    opus_cost_usd: data.opus_cost_usd,
    patch_error: patchError,
    http_status: patchError ? 500 : 200,
    via_webhook: data.via_webhook
  }
}];
